parameters.jsCode:
// Extract HTML from OpenRouter response
const resp = $input.first().json;
const html = resp.choices?.[0]?.message?.content || '';
const eval_data = $('Webhook: Generate CV').first().json.body?.eval || {};
const company = (eval_data.company || 'company').toLowerCase().replace(/[^a-z0-9]+/g, '-');
const date = new Date().toISOString().split('T')[0];
const filename = `cv-christiaan-verhoef-${company}-${date}.pdf`;

return [{ json: { html, filename, company, date, eval_data } }];
